app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# In-memory storage
clients = {}
authorization_codes = {}
access_tokens = {}
refresh_tokens = {}

# Client registration
def register_client(client_id, client_secret, redirect_uri_base, client_name):
    clients[client_id] = {
        'client_secret': client_secret,
        'redirect_uri_base': redirect_uri_base,
        'client_name': client_name
    }

# Pre-register some clients for testing
