@app.route('/authorize')
def authorize():
    response_type = request.args.get('response_type')
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    state = request.args.get('state', '')
    scope = request.args.get('scope', '')
    
    # Validate parameters
    if not response_type or not client_id or not redirect_uri:
        return jsonify({'error': 'invalid_request', 'error_description': 'Missing required parameters'}), 400
    
    if response_type != 'code':
        return jsonify({'error': 'unsupported_response_type'}), 400
    
    if client_id not in clients:
        return jsonify({'error': 'invalid_client', 'error_description': 'Unknown client'}), 400
    
    # Validate redirect URI using substring matching
    if not validate_redirect_uri(client_id, redirect_uri):
        return jsonify({
            'error': 'invalid_redirect_uri',
            'error_description': f'Redirect URI must start with {clients[client_id]["redirect_uri_base"]}'
        }), 400
    
    # Store authorization request in session
    session['auth_request'] = {
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'state': state,
        'scope': scope
    }
    
    # Show consent page
    client_name = clients[client_id]['client_name']
    template = '''
    <!DOCTYPE html>
    <html>
    <head><title>Authorization Request</title></head>
    <body>
        <h2>Authorization Request</h2>
        <p><b>{{ client_name }}</b> is requesting access to your account.</p>
        <p><b>Redirect URI:</b> {{ redirect_uri }}</p>
        <p><b>Scope:</b> {{ scope or 'default' }}</p>
        <form method="post" action="/authorize/consent">
            <button type="submit" name="approve" value="yes">Approve</button>
            <button type="submit" name="approve" value="no">Deny</button>
        </form>
    </body>
    </html>
    '''
    return render_template_string(template, 
                                  client_name=client_name,
                                  redirect_uri=redirect_uri,
                                  scope=scope)

@app.route('/authorize/consent', methods=['POST'])
def authorize_consent():
    if 'auth_request' not in session:
        return jsonify({'error': 'invalid_request'}), 400
    
    auth_request = session.pop('auth_request')
    approve = request.form.get('approve')
    
    redirect_uri = auth_request['redirect_uri']
    state = auth_request['state']
    
    if approve != 'yes':
        # User denied
        error_uri = f"{redirect_uri}?error=access_denied&state={state}"
        return redirect(error_uri)
    
    # Generate authorization code
    code = generate_authorization_code()
    authorization_codes[code] = {
        'client_id': auth_request['client_id'],
        'redirect_uri': redirect_uri,
        'scope': auth_request['scope'],
        'expires_at': datetime.utcnow() + timedelta(minutes=10),
        'used': False
    }
    
    # Redirect back to client with authorization code
    callback_uri = f"{redirect_uri}?code={code}&state={state}"
    return redirect(callback_uri)

@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    
    if grant_type == 'authorization_code':
        return handle_authorization_code_grant()
    elif grant_type == 'refresh_token':
        return handle_refresh_token_grant()
    else:
        return jsonify({'error': 'unsupported_grant_type'}), 400

def handle_authorization_code_grant():
    code = request.form.get('code')
    redirect_uri = request.form.get('redirect_uri')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    
    # Validate client credentials
    if client_id not in clients or clients[client_id]['client_secret'] != client_secret:
        return jsonify({'error': 'invalid_client'}), 401
    
    # Validate authorization code
    if code not in authorization_codes:
        return jsonify({'error': 'invalid_grant', 'error_description': 'Invalid authorization code'}), 400
    
    code_data = authorization_codes[code]
    
    # Check if code has been used
    if code_data['used']:
        return jsonify({'error': 'invalid_grant', 'error_description': 'Authorization code already used'}), 400
    
    # Check if code has expired
    if datetime.utcnow() > code_data['expires_at']:
        return jsonify({'error': 'invalid_grant', 'error_description': 'Authorization code expired'}), 400
    
    # Check if client_id matches
    if code_data['client_id'] != client_id:
        return jsonify({'error': 'invalid_grant', 'error_description': 'Client mismatch'}), 400
    
    # Validate redirect_uri using substring matching
    if not validate_redirect_uri(client_id, redirect_uri):
        return jsonify({'error': 'invalid_grant', 'error_description': 'Invalid redirect_uri'}), 400
    
    # Check if redirect_uri matches the one used during authorization
    if code_data['redirect_uri'] != redirect_uri:
        return jsonify({'error': 'invalid_grant', 'error_description': 'Redirect URI mismatch'}), 400
    
    # Mark code as used
    code_data['used'] = True
    
    # Generate tokens
    access_token = generate_access_token()
    refresh_token = generate_refresh_token()
    
    access_tokens[access_token] = {
        'client_id': client_id,
        'scope': code_data['scope'],
        'expires_at': datetime.utcnow() + timedelta(hours=1)
    }
    
    refresh_tokens[refresh_token] = {
        'client_id': client_id,
        'scope': code_data['scope'],
        'access_token': access_token
    }
    
    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer',
        'expires_in': 3600,
        'refresh_token': refresh_token,
        'scope': code_data['scope']
    })

def handle_refresh_token_grant():
    refresh_token = request.form.get('refresh_token')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    
    # Validate client credentials
    if client_id not in clients or clients[client_id]['client_secret'] != client_secret:
        return jsonify({'error': 'invalid_client'}), 401
    
    # Validate refresh token
    if refresh_token not in refresh_tokens:
        return jsonify({'error': 'invalid_grant'}), 400
    
    token_data = refresh_tokens[refresh_token]
    
    if token_data['client_id'] != client_id:
        return jsonify({'error': 'invalid_grant'}), 400
    
    # Revoke old access token
    old_access_token = token_data['access_token']
    if old_access_token in access_tokens:
        del access_tokens[old_access_token]
    
    # Generate new access token
    new_access_token = generate_access_token()
    
    access_tokens[new_access_token] = {
        'client_id': client_id,
        'scope': token_data['scope'],
        'expires_at': datetime.utcnow() + timedelta(hours=1)
    }
    
    token_data['access_token'] = new_access_token
    
    return jsonify({
        'access_token': new_access_token,
        'token_type': 'Bearer',
        'expires_in': 3600,
        'refresh_token': refresh_token,
        'scope': token_data['scope']
    })

@app.route('/userinfo')
def userinfo():
    auth_header = request.headers.get('Authorization', '')
    
    if not auth_header.startswith('Bearer '):
        return jsonify({'error': 'invalid_token'}), 401
    
    access_token = auth_header[7:]
    
    if access_token not in access_tokens:
        return jsonify({'error': 'invalid_token'}), 401
    
    token_data = access_tokens[access_token]
    
    if datetime.utcnow() > token_data['expires_at']:
        return jsonify({'error': 'invalid_token', 'error_description': 'Token expired'}), 401
    
    return jsonify({
        'sub': '12345',
        'name': 'Test User',
        'email': 'test@example.com',
        'client_id': token_data['client_id']
    })

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    
    client_name = data.get('client_name')
    redirect_uri_base = data.get('redirect_uri_base')
    
    if not client_name or not redirect_uri_base:
        return jsonify({'error': 'invalid_request'}), 400
    
    client_id = secrets.token_urlsafe(16)
    client_secret = secrets.token_urlsafe(32)
    
    register_client(client_id, client_secret, redirect_uri_base, client_name)
    
    return jsonify({
        'client_id': client_id,
        'client_secret': client_secret,
        'client_name': client_name,
        'redirect_uri_base': redirect_uri_base
    })

@app.route('/introspect', methods=['POST'])
def introspect():
    token = request.form.get('token')
    
    if token in access_tokens:
        token_data = access_tokens[token]
        active = datetime.utcnow() <= token_data['expires_at']
        
        return jsonify({
            'active': active,
            'client_id': token_data['client_id'],
            'scope': token_data['scope'],
            'exp': int(token_data['expires_at'].timestamp())
        })
    
    return jsonify({'active': False})

